// Generated by Gemini and lightly edited.
import { css, html, Wrec } from "wrec"; // was importing from a CDN

class LabeledSwitch extends Wrec {
  // 1. Define component properties (mapped to attributes)
  static properties = {
    label: { type: String, value: "Switch" },
    checked: { type: Boolean, value: false },
  };

  // 2. Define scoped CSS
  // Note: 'this.checked' is reactive within the CSS block!
  static css = css`
    :host {
      display: inline-flex;
      align-items: center;
      gap: 12px;
      font-family: sans-serif;
      cursor: pointer;
      user-select: none;
    }

    .track {
      width: 40px;
      height: 20px;
      background-color: #ccc;
      border-radius: 20px;
      position: relative;
      transition: background-color 0.3s;
    }

    /* Reference component properties directly in CSS */
    .track[data-on="data-on"] {
      /* was .track[data-on="true"] { */
      background-color: #4caf50;
    }

    .thumb {
      width: 16px;
      height: 16px;
      background-color: white;
      border-radius: 50%;
      position: absolute;
      top: 2px;
      left: 2px;
      transition: transform 0.3s;
    }

    .track[data-on="data-on"] .thumb {
      /* was .track[data-on="true"] .thumb { */
      transform: translateX(20px);
    }
  `;

  // 3. Define the HTML structure
  // 'onClick' is automatically wired to the toggle method
  static html = html`
    <span>this.label</span>
    <div class="track" data-on="this.checked" onClick="toggle">
      <div class="thumb"></div>
    </div>
  `;

  // 4. Define methods
  toggle() {
    this.checked = !this.checked;

    // Optional: Dispatch a custom event for parents to listen to
    this.dispatchEvent(
      new CustomEvent("switch-change", {
        detail: { checked: this.checked },
        bubbles: true,
        composed: true,
      }),
    );
  }
}

// Register the component as <labeled-switch>
LabeledSwitch.register();
